import React from 'react';
import './TrustBadge.css';

/**
 * TrustBadge — Feature 1
 * Displays a colored trust badge based on campaign trustScore (0–100)
 * Props:
 *   score: number (0-100)
 *   size: 'sm' | 'md' (default: 'md')
 */
const TrustBadge = ({ score = 0, size = 'md' }) => {
  let tier, emoji, className;

  if (score >= 71) {
    tier = 'Trusted Campaign';
    emoji = '✅';
    className = 'trust-badge trust-badge--green';
  } else if (score >= 41) {
    tier = 'Partially Verified';
    emoji = '🔶';
    className = 'trust-badge trust-badge--yellow';
  } else {
    tier = 'Unverified';
    emoji = '⚠️';
    className = 'trust-badge trust-badge--red';
  }

  return (
    <span className={`${className} trust-badge--${size}`} title={`Trust Score: ${score}/100`}>
      {emoji} {tier}
      <span className="trust-score-num">{score}</span>
    </span>
  );
};

export default TrustBadge;
